import json

def check_args(tool_name: str, received: dict, tools: list) -> list[str]:
    """Light validation of generated arguments — checks required fields and types."""
    schema = next((t["input_schema"] for t in tools if t["name"] == tool_name), None)
    if not schema:
        return [f"Unknown tool: {tool_name}"]

    errors = []
    required = schema.get("required", [])
    props = schema.get("properties", {})

    for field in required:
        if field not in received:
            errors.append(f"Missing required field: {field}")

    for field, value in received.items():
        if field not in props:
            errors.append(f"Unexpected field: {field}")
            continue
        expected_type = props[field].get("type")
        py_type = {"string": str, "integer": int, "number": (int, float),
                   "boolean": bool, "array": list, "object": dict}.get(expected_type)
        if py_type and not isinstance(value, py_type):
            errors.append(f"Field {field!r}: expected {expected_type}, got {type(value).__name__}")

    return errors

# In the dispatch loop
