# Pattern: pre-fill arguments from server-side context
# to prevent the model from needing to produce them.

def build_messages_with_context(user_msg: str, user_id: str) -> list[dict]:
    """Inject server-known values as system context so the model doesn't guess."""
    return [
        {
            "role": "user",
            "content": [
                {
                    "type": "text",
                    "text": (
                        f"[Context: authenticated user_id = {user_id!r}, "
                        f"account_email = {get_email(user_id)!r}. "
                        "Use these values when tools require them.]"
                    )
                },
                {"type": "text", "text": user_msg}
            ]
        }
    ]

# Now the model will use the injected user_id and email
